        Py_XDECREF(w);
        Py_XDECREF(cov);
        return NULL;
    }

    npy_intp n = PyArray_DIM(w, 0);
    const double *x = (const double*)PyArray_DATA(w);
    const double *S = (const double*)PyArray_DATA(cov);

    // risk_squared = sum_i x[i] * (sum_j S[i][j] * x[j])
    double risk_squared = 0.0;
    for (npy_intp i = 0; i < n; i++) {
        const double *row = S + i * n;
        double row_sum = 0.0;
        for (npy_intp j = 0; j < n; j++) {
            row_sum += row[j] * x[j];
        }
        risk_squared += x[i] * row_sum;
    }

    Py_DECREF(w);
    Py_DECREF(cov);

    return PyFloat_FromDouble(sqrt(risk_squared));
}

